const data = $json || {};
const sleep = data.sleep_analysis || [];
const rhr = data.resting_heart_rate || [];
const hrv = data.heart_rate_variability || [];

if (!Array.isArray(sleep) || sleep.length === 0) {
  return [{ json: { hasData: false } }];
}

// entries are sorted newest-first by the storage backend
const latestSleep = sleep[0];
const latestRhr = Array.isArray(rhr) && rhr.length ? rhr[0] : null;
const latestHrv = Array.isArray(hrv) && hrv.length ? hrv[0] : null;

const inBedH = (latestSleep.inBed || 0);
const totalH = (latestSleep.core||0)+(latestSleep.deep||0)+(latestSleep.rem||0);
const deepH = (latestSleep.deep||0);
const remH = (latestSleep.rem||0);
const coreH = (latestSleep.core||0);
const awakeMin = Math.round((latestSleep.awake||0)*60);

const fmtTime = (iso) => iso ? new Date(iso).toLocaleTimeString('de-DE',{hour:'2-digit',minute:'2-digit'}) : '?';

let summary = `🛏️ Bettzeit: ${inBedH.toFixed(1)} h (${fmtTime(latestSleep.inBedStart)} - ${fmtTime(latestSleep.inBedEnd)})
😴 Gesamtschlaf: ${totalH.toFixed(1)} h
🔵 Tiefschlaf: ${deepH.toFixed(1)} h | REM: ${remH.toFixed(1)} h | Leicht: ${coreH.toFixed(1)} h
⚠️ Wach im Bett: ${awakeMin} min`;
if (latestRhr) summary += `\n❤️ Ruhepuls: ${latestRhr.value ?? latestRhr.qty} bpm`;
if (latestHrv) summary += `\n📈 HRV: ${Math.round(latestHrv.value ?? latestHrv.qty)} ms`;

const tips = [];
if (totalH < 6) {
  tips.push(`Nur ${totalH.toFixed(1)}h Schlaf - versuch heute 45-60 Min frueher ins Bett zu gehen.`);
} else if (totalH < 7) {
  tips.push(`Mit ${totalH.toFixed(1)}h etwas knapp - eine frueher Bettzeit wuerde guttun.`);
} else {
  tips.push(`Guter Schlafumfang (${totalH.toFixed(1)}h) - weiter so.`);
}
if (deepH < 1) {
  tips.push('Wenig Tiefschlaf - heute Abend Alkohol, spaetes Essen und Bildschirmzeit vor dem Schlafen meiden.');
}
if (awakeMin > 30) {
  tips.push(`${awakeMin} Min wach im Bett - Raumtemperatur und Laerm im Schlafzimmer pruefen.`);
}
if (remH < 1) {
  tips.push('Wenig REM-Schlaf - Stresslevel vorm Schlafengehen (z.B. kurze Atemuebung) senken kann helfen.');
}

const empfehlung = tips.join('\n');

return [{ json: { hasData: true, summary, empfehlung } }];

